[
  {
    "id": "conflict-001",
    "title": "设备产能是否达到合同约定",
    "description": "海川食品主张设备经两次共同测试平均产能分别为5200瓶/小时和5700瓶/小时，均未达合同约定的6000瓶/小时，构成质量不合格；华东智能装备主张产能差距由买方瓶体规格、原料黏度及现场供电波动等条件造成，设备本身无质量问题。双方对未达标原因归属存在直接分歧。",
    "actorIds": ["actor-001", "actor-002"]
  },
  {
    "id": "conflict-002",
    "title": "交付是否逾期及尾款支付条件",
    "description": "设备于2026年3月18日交付，较合同约定的2026年3月15日迟延3日，双方均已签字签收。海川食品以设备未通过验收为由暂缓支付12万元尾款，华东智能装备则主张已完成交付和调试，要求买方按约支付尾款。双方对迟延交付的法律评价及尾款支付条件是否已成就存在分歧。",
    "actorIds": ["actor-001", "actor-002"]
  },
  {
    "id": "conflict-003",
    "title": "整改效果及后续处理方式",
    "description": "华东智能装备于2026年3月22日调整设备参数并更换部分导轨后，2026年3月25日复测平均产能为5700瓶/小时，仍未达6000瓶/小时。海川食品认为整改无效、设备本身存在质量和性能问题，要求继续整改；华东智能装备认为其已履行整改义务，进一步差距仍由买方现场条件造成，应由买方配合改善并支付尾款。双方对整改是否充分及下一步处理方式存在分歧。",
    "actorIds": ["actor-001", "actor-002"]
  }
]
